	@Test
	void deterministicGreedySeedSupportsArbitraryFactorCountsWithoutLongMasks()
			throws ReflectiveOperationException {
		Class<?> seedType = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.DeterministicGreedyJoinSeed");
		Method expressions = seedType.getMethod("expressions", JoinRegion.class, JoinSearchContext.class,
				ToDoubleFunction.class, ToDoubleFunction.class);
		for (int factorCount : List.of(65, 128)) {
			JoinRegion region = chainRegion(factorCount);
			JoinSearchContext context = chainContext(region);
			ToDoubleFunction<JoinFactor> rows = ignored -> 1.0d;
			ToDoubleFunction<JoinFactor> work = factor -> factor.occurrenceId() == factorCount - 1
					? 1.0d
					: 1_000.0d + factor.occurrenceId();

			@SuppressWarnings("unchecked")
			List<JoinMemoExpression> first = (List<JoinMemoExpression>) expressions.invoke(null, region, context,
					rows, work);
			@SuppressWarnings("unchecked")
			List<JoinMemoExpression> second = (List<JoinMemoExpression>) expressions.invoke(null, region, context,
					rows, work);

			List<Integer> expectedOrder = new ArrayList<>(factorCount);
			for (int occurrenceId = 0; occurrenceId < factorCount; occurrenceId++) {
				expectedOrder.add(occurrenceId);
			}
			Collections.reverse(expectedOrder);
			assertEquals(factorCount - 1, first.size());
			assertEquals(expectedOrder, first.getLast().representativeTree().leafOrder(),
					"The cheapest end of a connected chain must seed a stable connected order");
			assertEquals(first, second, "Repeated seed construction must be deterministic");
			assertTrue(first.stream().allMatch(region::isLegal));
		}
	}

	@Test
	void deterministicGreedyOrderUsesPrimitiveStateAndExactWorkCounters() throws ReflectiveOperationException {
		int factorCount = 128;
		JoinRegion region = chainRegion(factorCount);
		JoinSearchContext context = chainContext(region);
		AtomicInteger rowReads = new AtomicInteger();
		AtomicInteger workReads = new AtomicInteger();
		ToDoubleFunction<JoinFactor> rows = factor -> {
			rowReads.incrementAndGet();
			return 1.0d;
		};
		ToDoubleFunction<JoinFactor> work = factor -> {
			workReads.incrementAndGet();
			return factorCount - factor.occurrenceId();
		};
		Class<?> seedType = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.DeterministicGreedyJoinSeed");
		Method buildOrder = seedType.getMethod("buildOrder", JoinRegion.class, JoinSearchContext.class,
				ToDoubleFunction.class, ToDoubleFunction.class);

		Object seedOrder = buildOrder.invoke(null, region, context, rows, work);
		int[] occurrenceIds = (int[]) seedOrder.getClass().getMethod("occurrenceIds").invoke(seedOrder);
		Object metrics = seedOrder.getClass().getMethod("metrics").invoke(seedOrder);
		long selectionVisits = (long) metrics.getClass().getMethod("selectionVisits").invoke(metrics);
		long adjacencyArcVisits = (long) metrics.getClass().getMethod("adjacencyArcVisits").invoke(metrics);

		int[] expected = new int[factorCount];
		for (int index = 0; index < factorCount; index++) {
			expected[index] = factorCount - index - 1;
		}
		assertArrayEquals(expected, occurrenceIds);
		assertEquals((long) factorCount * (factorCount + 1L) / 2L, selectionVisits);
		assertEquals(2L * (factorCount - 1L), adjacencyArcVisits);
		assertEquals(factorCount, rowReads.get());
		assertEquals(factorCount, workReads.get());
	}

