	@Test
	void reservedGreedySeedInstallsExecutableChainBeforeExploratoryWork() {
		JoinRegion region = chainRegion(3);
		JoinSearchContext context = chainContext(region);
		SearchWorkLedger work = new SearchWorkLedger(
				new SearchLimits(1_000L, 0L, 0L, 0L, 0L, 100L, 16L));
		ScopedJoinSearch search = new ScopedJoinSearch(region,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.auto(16L, 100L),
				work,
				providerWithUnreservedAlternate(),
				OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		for (JoinFactor factor : region.factors()) {
			int occurrenceId = factor.occurrenceId();
			search.seedFactor(factor.occurrenceId(),
					factorWinner(4_000 + occurrenceId, factor.groupId(),
							pattern("v" + occurrenceId, "p" + occurrenceId, "v" + (occurrenceId + 1)),
							PhysicalProperties.ANY),
					ProvidedPhysicalProperties.ANY);
		}
		JoinSearchRequest request = JoinSearchRequest.boundedEnumeration(region, 0L,
				JoinSearchDependencyStamp.EMPTY, 100L, context);

		new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor()))
				.enumerateScopedMemoExpressions(request, work, search);

		assertEquals(1, search.rootCandidateIds(1).size(),
				() -> "The reserved seed must be physically executable before contributors can spend exploratory work; "
						+ "candidates=" + search.memo().candidateCount()
						+ ", enforceableRoots=" + search.enforceableRootCandidateIds(1));
		assertEquals(5, search.memo().candidateCount(), "Three factor states plus one candidate for each seed link");
		assertEquals(0L, work.counterSnapshot().candidateEvaluations(),
				"The single reserved physical chain is outside the exploratory candidate budget");
		assertFalse(search.drain(), "Every non-reserved implementation remains subject to the zero candidate budget");
		assertEquals(5, search.memo().candidateCount(), "Draining must not add an uncounted alternate seed frontier");
		assertEquals(Set.of(OptimizationLimitCause.PARTITION_PROBES, OptimizationLimitCause.CANDIDATE_EVALUATIONS),
				work.limitCauses());
	}

	@Test
	void primitiveDphypSeedsFullRegionBeforeRefiningFrontierProducts() {
		JoinRegion region = chainRegion(3);
		JoinSearchContext context = chainContext(region);
		SearchWorkLedger work = new SearchWorkLedger(new SearchLimits(100L, 10L, 10L, 4L, 10L, 100L, 16L));
		ScopedJoinSearch search = new ScopedJoinSearch(region, context,
				CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT), JoinRegionMemo.Retention.auto(16L, 100L),
				work, priorityProbeProvider(), OptimizationGoal.root(), RequiredPhysicalProperties.ANY);
		for (JoinFactor factor : region.factors()) {
			for (int variant = 0; variant < 4; variant++) {
				PhysicalProperties delivered = PhysicalProperties.builder()
						.accessPath("factor-" + factor.occurrenceId() + '-' + variant)
						.build();
				Winner winner = factorWinner(5_000 + factor.occurrenceId() * 10 + variant, factor.groupId(),
						pattern("v" + factor.occurrenceId(), "p" + factor.occurrenceId(),
								"v" + (factor.occurrenceId() + 1)),
						delivered);
				search.seedFactor(factor.occurrenceId(), winner,
						TypedPhysicalPropertyBridge.provided(delivered, context.bindingUniverse(),
								winner.physicalOperatorId()));
			}
		}
		PrimitiveDphypJoinSearchContributor dphyp = new PrimitiveDphypJoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("priority-dphyp", Coverage.EXHAUSTIVE_CONNECTED, 10);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				return Outcome.unsupported("scoped route must not request a privately selected DPhyp tree");
			}

			@Override
			public long configuredPairProbeLimit() {
				return 10L;
			}

			@Override
			public Outcome contributePartitions(JoinSearchRequest request, java.util.function.LongPredicate hasCandidate,
					PartitionSink sink) {
				if (sink.accept(0b100L, 0b010L) || !hasCandidate.test(0b110L)) {
					return Outcome.budgetExhausted("two-factor DPhyp seed was not retained");
				}
				if (sink.accept(0b110L, 0b001L)) {
					return Outcome.budgetExhausted("full-region DPhyp seed was not retained");
				}
				return Outcome.completed();
			}
		};
		JoinSearchRequest request = JoinSearchRequest.boundedEnumeration(region, 0L,
				JoinSearchDependencyStamp.EMPTY, 100L, context);

		new JoinSearchService(List.of(dphyp)).enumerateScopedMemoExpressions(request, work, search);

		assertTrue(search.rootCandidateIds(Integer.MAX_VALUE)
				.stream()
				.map(search.memo()::candidate)
				.map(candidate -> candidate.recipe())
				.anyMatch(recipe -> recipe instanceof JoinRegionRecipe.Join join
						&& "priority-dphyp".equals(join.contributorId())),
				"Primitive DPhyp must seed a complete candidate before bounded refinement expands frontier products");
		assertEquals(4L, work.counterSnapshot().candidateEvaluations(),
				"One cheapest child-frontier pair should be charged per streamed subset and physical orientation");
	}

	private static JoinImplementationProvider priorityProbeProvider() {
		AtomicInteger expressionIds = new AtomicInteger(6_000);
		return request -> List.of(new JoinImplementationProvider.Implementation() {
			@Override
			public String id() {
				return "priority-probe";
			}

			@Override
			public Optional<JoinImplementationProvider.Result> evaluate(JoinImplementationProvider.Request input) {
				TupleExpr plan = new Join(input.left().winner().plan().clone(), input.right().winner().plan().clone());
				double localWork = "priority-dphyp".equals(input.contributorId()) ? 0.0d : 100.0d;
				double totalWork = input.left().winner().cost().workRows()
						+ input.right().winner().cost().workRows() + localWork;
				CostVector cost = new CostVector(1.0d, totalWork, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d);
				MemoExpr expression = MemoExpr.physical(expressionIds.getAndIncrement(),
						1_000_000_000 + input.resultGroupId(), plan,
						List.of(input.left().winner().expression().groupId(),
								input.right().winner().expression().groupId()),
						"priority-probe", PhysicalProperties.ANY,
						List.of(PhysicalProperties.ANY, PhysicalProperties.ANY), RuleKind.IMPLEMENTATION,
						cost, List.of(), EstimateSnapshot.cascades(cost), MemoExpr.ImplementationForm.TRANSPARENT);
				Winner winner = new Winner(expression, plan, PhysicalProperties.ANY, cost, List.of(), false, "");
				return Optional.of(new JoinImplementationProvider.Result(winner, ProvidedPhysicalProperties.ANY,
						new JoinRegionRecipe.Join(input.contributorId())));
			}
		});
	}

	private static JoinImplementationProvider providerWithUnreservedAlternate() {
		JoinImplementationProvider delegate = new CascadesJoinImplementationProvider(
				CascadesCostModel.from(new EvaluationStatistics()), BindingUniverse.create());
		return request -> {
			List<JoinImplementationProvider.Implementation> implementations = new ArrayList<>();
			delegate.implementations(request).forEach(implementations::add);
			JoinImplementationProvider.Implementation reserved = implementations.getFirst();
			JoinImplementationProvider.Implementation alternate = new JoinImplementationProvider.Implementation() {

				@Override
				public String id() {
					return "unreserved-alternate";
				}

				@Override
				public Optional<JoinImplementationProvider.Result> evaluate(
						JoinImplementationProvider.Request alternateRequest) {
					return reserved.evaluate(alternateRequest);
				}
			};
			implementations.add(alternate);
			return implementations;
		};
	}

	@Test
	void exactPartitionLimitStopsBeforeOvershootAndDoesNotRetry() {
		SearchLimits limits = new SearchLimits(32L, Long.MAX_VALUE, 1L, Long.MAX_VALUE, Long.MAX_VALUE,
				Long.MAX_VALUE, Long.MAX_VALUE);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(new StandardCascadesRules.GenericImplementationRule()).build(),
				CascadesTelemetry.NO_OP, limits);

		CascadesPlan plan = planner.optimize(threeFactorJoin(), OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.RESOURCE_LIMIT_EXCEEDED, plan.completeness());
		assertEquals(1L, plan.searchStatus().counters().partitionProbes(),
				"The denied partition must not overshoot the deterministic limit");
		assertEquals(Set.of(OptimizationLimitCause.PARTITION_PROBES), plan.searchStatus().limitCauses(),
				"A hard join limit must stop exact retry before it also exhausts rule work");
		assertTrue(plan.pendingTasks()
				.stream()
				.anyMatch(task -> task.kind() == PendingOptimizationTask.Kind.ENUMERATE_JOIN));
	}

	@Test
	void sixteenFactorCliqueExactIsTransactionalAtPartitionLimit() {
		long partitionLimit = 64L;
		SearchLimits limits = new SearchLimits(10_000L, Long.MAX_VALUE, partitionLimit, Long.MAX_VALUE,
				Long.MAX_VALUE, Long.MAX_VALUE, Long.MAX_VALUE);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(new StandardCascadesRules.GenericImplementationRule()).build(),
				CascadesTelemetry.NO_OP, limits);
		TupleExpr input = cliqueJoin(16);
		String originalTopology = topologyFingerprint(input);

		CascadesPlan plan = planner.optimize(input, OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.RESOURCE_LIMIT_EXCEEDED, plan.completeness());
		assertEquals(partitionLimit, plan.searchStatus().counters().partitionProbes(),
				"EXACT must stop before the first partition probe that would overshoot its limit");
		assertEquals(Set.of(OptimizationLimitCause.PARTITION_PROBES), plan.searchStatus().limitCauses());
		assertEquals(originalTopology, topologyFingerprint(input),
				"an incomplete exact search must not mutate the caller's sixteen-factor algebra");
		assertTrue(plan.pendingTasks()
				.stream()
				.anyMatch(task -> task.kind() == PendingOptimizationTask.Kind.ENUMERATE_JOIN));
	}

